<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>WastedToken Mint — Collectible Challenge Coins</title>
<style>
:root {
  --bg: #0a0a0c;
  --fg: #e8e6e3;
  --muted: #6b6b70;
  --accent: #c9a84c;
  --accent-dim: #8b7a3d;
  --card: #141418;
  --border: #2a2a30;
  --sold: #4a1a1a;
  --coming: #1a3a4a;
}
* { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; }
body {
  font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  background: var(--bg);
  color: var(--fg);
  line-height: 1.6;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}
a { color: var(--accent); text-decoration: none; }
a:hover { text-decoration: underline; }

/* Hero */
.hero {
  position: relative;
  width: 100%;
  min-height: 70vh;
  max-height: 900px;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
}
.hero::before {
  content: '';
  position: absolute;
  inset: 0;
  background:
    radial-gradient(ellipse 80% 60% at 50% 30%, rgba(201,168,76,0.08) 0%, transparent 70%),
    radial-gradient(ellipse 60% 40% at 50% 80%, rgba(201,168,76,0.04) 0%, transparent 60%);
  pointer-events: none;
}
#coin-hero {
  display: block;
  width: 100%;
  height: 100%;
  max-width: 600px;
  max-height: 600px;
  filter: drop-shadow(0 30px 60px rgba(0,0,0,0.5));
}
.hero-badge {
  position: absolute;
  bottom: 2rem;
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  gap: 1rem;
  flex-wrap: wrap;
  justify-content: center;
  padding: 0 1rem;
  pointer-events: none;
}
.badge {
  background: rgba(20,20,24,0.9);
  border: 1px solid var(--border);
  padding: 0.5rem 1rem;
  border-radius: 100px;
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--muted);
  backdrop-filter: blur(10px);
}
.badge.gold { border-color: var(--accent); color: var(--accent); }
.badge.black { border-color: #3a3a3a; color: #888; }

/* Sections */
section { padding: 5rem 1.5rem; max-width: 1100px; margin: 0 auto; width: 100%; }
.section-header { text-align: center; margin-bottom: 3rem; }
.section-header h2 {
  font-size: clamp(2rem, 5vw, 3rem);
  font-weight: 700;
  letter-spacing: -0.02em;
  background: linear-gradient(135deg, var(--fg) 0%, var(--accent) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.section-header p { color: var(--muted); font-size: 1.1rem; max-width: 600px; margin: 1rem auto 0; }

/* About */
.about-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 2rem;
}
.about-card {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 2rem;
  transition: transform 0.3s ease, border-color 0.3s ease, box-shadow 0.3s ease;
}
.about-card:hover {
  transform: translateY(-4px);
  border-color: var(--accent-dim);
  box-shadow: 0 20px 40px rgba(0,0,0,0.3);
}
.about-icon {
  width: 48px;
  height: 48px;
  margin-bottom: 1rem;
  opacity: 0.8;
}
.about-card h3 { font-size: 1.25rem; font-weight: 600; margin-bottom: 0.75rem; }
.about-card p { color: var(--muted); font-size: 0.95rem; line-height: 1.7; }

/* Collection */
.collection-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
  gap: 1.5rem;
}
.edition {
  position: relative;
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 16px;
  overflow: hidden;
  display: flex;
  flex-direction: column;
  transition: transform 0.3s ease, border-color 0.3s ease, box-shadow 0.3s ease;
}
.edition:hover {
  transform: translateY(-4px);
  border-color: var(--accent-dim);
  box-shadow: 0 20px 40px rgba(0,0,0,0.3);
}
.edition[data-state="sold-out"] { border-color: var(--sold); }
.edition[data-state="coming-soon"] { border-color: var(--coming); }
.edition-canvas {
  display: block;
  width: 100%;
  aspect-ratio: 1;
  background: linear-gradient(135deg, #1a1a1e 0%, #0f0f12 100%);
}
.edition-info { padding: 1.5rem; flex: 1; display: flex; flex-direction: column; }
.edition-name {
  font-size: 1.1rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 0.25rem;
}
.edition-metal { color: var(--muted); font-size: 0.85rem; margin-bottom: 1rem; }
.edition-status {
  font-size: 0.75rem;
  font-weight: 700;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  padding: 0.35rem 0.75rem;
  border-radius: 100px;
  width: fit-content;
  margin-bottom: 1rem;
}
.edition[data-state="available"] .edition-status {
  background: rgba(201,168,76,0.15);
  color: var(--accent);
  border: 1px solid var(--accent-dim);
}
.edition[data-state="sold-out"] .edition-status {
  background: rgba(74,26,26,0.5);
  color: #ff6b6b;
  border: 1px solid #8b3a3a;
}
.edition[data-state="coming-soon"] .edition-status {
  background: rgba(26,58,74,0.5);
  color: #64b5f6;
  border: 1px solid #2a6b8a;
}
.edition-desc { color: var(--muted); font-size: 0.9rem; line-height: 1.6; margin-bottom: 1.5rem; flex: 1; }
.buy {
  width: 100%;
  padding: 0.875rem 1.5rem;
  background: linear-gradient(135deg, var(--accent) 0%, var(--accent-dim) 100%);
  border: none;
  border-radius: 10px;
  color: #0a0a0c;
  font-weight: 700;
  font-size: 0.9rem;
  letter-spacing: 0.02em;
  cursor: pointer;
  transition: transform 0.15s ease, box-shadow 0.15s ease, filter 0.15s ease;
}
.buy:hover:not(:disabled) { transform: translateY(-2px); box-shadow: 0 8px 24px rgba(201,168,76,0.3); }
.buy:active:not(:disabled) { transform: translateY(0); }
.buy:disabled {
  opacity: 0.4;
  cursor: not-allowed;
  background: #2a2a30;
  color: var(--muted);
}
.edition[data-state="sold-out"] .buy,
.edition[data-state="coming-soon"] .buy {
  display: none;
}

/* Footer */
footer {
  margin-top: auto;
  padding: 3rem 1.5rem;
  border-top: 1px solid var(--border);
  text-align: center;
  color: var(--muted);
  font-size: 0.85rem;
}
footer a { color: var(--muted); }
footer a:hover { color: var(--accent); }

/* Reduced motion */
@media (prefers-reduced-motion: reduce) {
  .hero, .edition, .about-card { animation: none !important; transition: none !important; }
}

/* Responsive */
@media (max-width: 640px) {
  section { padding: 3rem 1rem; }
  .hero { min-height: 50vh; }
}
</style>
</head>
<body>
<header class="hero">
  <canvas id="coin-hero"></canvas>
  <div class="hero-badge">
    <span class="badge">Physical Mint</span>
    <span class="badge gold">Limited Editions</span>
    <span class="badge black">Numbered Series</span>
  </div>
</header>

<main>
  <section id="about">
    <div class="section-header">
      <h2>About WastedToken Mint</h2>
      <p>Forging tangible value in a weightless world. Each coin is a covenant — metal, art, and scarcity bound together.</p>
    </div>
    <div class="about-grid">
      <article class="about-card">
        <svg class="about-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" aria-hidden="true"><path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"/></svg>
        <h3>Master Die Engraving</h3>
        <p>Every edition begins as a hand-cut master die, struck under 200 tons of pressure. No CNC shortcuts — only the slow, deliberate craft of the engraver's hand.</p>
      </article>
      <article class="about-card">
        <svg class="about-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" aria-hidden="true"><circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/></svg>
        <h3>Numbered Scarcity</h3>
        <p>Each coin bears a unique laser-etched serial on its edge. Mintage is fixed at launch — no re-strikes, no second runs. What's minted is all that exists.</p>
      </article>
      <article class="about-card">
        <svg class="about-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" aria-hidden="true"><path d="M21 12V7H5V6M16 1l4 4-4 4M12 4v16"/></svg>
        <h3>Vault-Grade Materials</h3>
        <p>Bronze, .999 silver, 24k gold plate, and blackened tungsten. Each metal chosen for weight, hand-feel, and how it ages — patina is a feature, not a flaw.</p>
      </article>
    </div>
  </section>

  <section id="collection">
    <div class="section-header">
      <h2>The Collection</h2>
      <p>Four editions. Three metals. One obsidian future. Choose your weight.</p>
    </div>
    <div class="collection-grid">
      <!-- Bronze -->
      <div class="edition" data-edition="bronze" data-state="available">
        <canvas class="edition-canvas"></canvas>
        <div class="edition-info">
          <div class="edition-name">Bronze Edition</div>
          <div class="edition-metal">Antique bronze • 45mm • 38g</div>
          <span class="edition-status">Available</span>
          <p class="edition-desc">The foundation of the series. Warm copper tones that deepen with every hand that holds it. Open edition — minted to demand.</p>
          <button class="buy">Add to cart — $45</button>
        </div>
      </div>
      <!-- Silver -->
      <div class="edition" data-edition="silver" data-state="available">
        <canvas class="edition-canvas"></canvas>
        <div class="edition-info">
          <div class="edition-name">Silver Edition</div>
          <div class="edition-metal">.999 fine silver • 45mm • 42g</div>
          <span class="edition-status">Available</span>
          <p class="edition-desc">Brilliant uncirculated strike on pure silver. Mirror fields, frosted devices. Each coin individually numbered on the edge. Limited to 2,500.</p>
          <button class="buy">Add to cart — $185</button>
        </div>
      </div>
      <!-- Gold -->
      <div class="edition" data-edition="gold" data-state="sold-out">
        <canvas class="edition-canvas"></canvas>
        <div class="edition-info">
          <div class="edition-name">Gold Edition</div>
          <div class="edition-metal">24k gold plate • 45mm • 40g</div>
          <span class="edition-status">SOLD OUT</span>
          <p class="edition-desc">Heavy 24k gold over brass core. The crown jewel of the first series. All 500 pieces claimed in 47 minutes. No re-mint planned.</p>
        </div>
      </div>
      <!-- Black -->
      <div class="edition" data-edition="black" data-state="coming-soon">
        <canvas class="edition-canvas"></canvas>
        <div class="edition-info">
          <div class="edition-name">Obsidian Edition</div>
          <div class="edition-metal">Blackened tungsten • 45mm • 58g</div>
          <span class="edition-status">MINTING AUTUMN</span>
          <p class="edition-desc">The heaviest coin we've ever struck. Tungsten core, PVD black finish, selective gold accent. The void stares back. Autumn 2025.</p>
        </div>
      </div>
    </div>
  </section>
</main>

<footer>
  <p>WastedToken Mint &copy; 2025. All coins struck in the USA. <a href="#">Terms</a> · <a href="#">Privacy</a> · <a href="#">Contact</a></p>
</footer>

