    multiply(q){ const x=this.x,y=this.y,z=this.z,w=this.w; const qx=q.x,qy=q.y,qz=q.z,qw=q.w; this.x=x*qw+w*qx+y*qz-z*qy; this.y=y*qw+w*qy+z*qx-x*qz; this.z=z*qw+w*qz+x*qy-y*qx; this.w=w*qw-x*qx-y*qy-z*qz; return this; }
  }

