      data[idx + 1] = Math.round((n.y * 0.5 + 0.5) * 255);
      data[idx + 2] = Math.round((n.z * 0.5 + 0.5) * 255);
      data[idx + 3] = 255;
    }
  }
  ctx.putImageData(imgData, 0, 0);
  return canvas;
}

function uploadTexture(gl, canvas) {
  const tex = gl.createTexture();
  gl.bindTexture(gl.TEXTURE_2D, tex);
  gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, canvas);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR_MIPMAP_LINEAR);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.REPEAT);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.REPEAT);
  gl.generateMipmap(gl.TEXTURE_2D);
  return tex;
}

// Front face: WastedToken Mint emblem
function createFrontNormalMap() {
  return createNormalMap(512, 512, (u, v) => {
    // Center coordinates
    const cx = u - 0.5;
    const cy = v - 0.5;
    const dist = Math.sqrt(cx * cx + cy * cy);
    const angle = Math.atan2(cy, cx);

    let height = 0;

    // Outer ring
    if (dist > 0.38 && dist < 0.45) {
      height += 0.15 * (1 - Math.abs(dist - 0.415) / 0.035);
    }

    // Inner circle
    if (dist < 0.28) {
      height += 0.12 * (1 - dist / 0.28);
    }

    // "W" shape in center
    if (dist < 0.22) {
      const w = Math.abs(Math.sin(angle * 4) * 0.5 + 0.5);
      const w2 = Math.abs(Math.sin(angle * 4 + 1.5) * 0.5 + 0.5);
      const wShape = Math.max(w, w2);
      height += 0.18 * wShape * (1 - dist / 0.22);
    }

    // Radial lines (sunburst)
    for (let i = 0; i < 16; i++) {
      const a = i * Math.PI / 8;
      const diff = Math.abs(angle - a);
      if (diff < 0.03 && dist > 0.28 && dist < 0.38) {
        height += 0.08 * (1 - diff / 0.03);
      }
    }

    // Text-like bands
    if (dist > 0.3 && dist < 0.35) {
      height += 0.06 * Math.sin(angle * 24) * 0.5 + 0.03;
    }

    // Convert height to normal
    const scale = 10.0;
    const du = (createNormalMap(1,1,(uu,vv)=>({x:0,y:0,z:1}))); // dummy
    // Compute derivatives via finite difference
    const eps = 1/512;
    const h = height;
    const hU = createNormalMap(1,1,(uu,vv)=>({x:0,y:0,z:1})); // placeholder

    // Simplified normal from height gradients
    const hx = Math.sin(angle * 32) * 0.02 + Math.cos(dist * 50) * 0.01;
    const hy = Math.cos(angle * 24) * 0.02 + Math.sin(dist * 40) * 0.01;

    const nx = -hx * scale;
    const ny = -hy * scale;
    const nz = 1.0;
    const len = Math.sqrt(nx*nx + ny*ny + nz*nz);
    return { x: nx/len, y: ny/len, z: nz/len };
  });
}

// Back face: "10,000 TOKENS" denomination
function createBackNormalMap() {
  return createNormalMap(512, 512, (u, v) => {
    const cx = u - 0.5;
    const cy = v - 0.5;
    const dist = Math.sqrt(cx * cx + cy * cy);
    const angle = Math.atan2(cy, cx);

    let height = 0;

    // Outer ring
    if (dist > 0.38 && dist < 0.45) {
      height += 0.15 * (1 - Math.abs(dist - 0.415) / 0.035);
    }

    // Large central number area
    if (dist < 0.35) {
      // Simulated "10,000" text block
      const tx = cx * 3.5;
      const ty = cy * 3.5;

      // "10,000" - five character blocks
      for (let i = 0; i < 5; i++) {
        const charX = tx - 1.2 + i * 0.6;
        const charDist = Math.sqrt(charX * charX + ty * ty);
        if (charDist < 0.25) {
          height += 0.18 * (1 - charDist / 0.25);
        }
      }

      // "TOKENS" below - smaller text
      const ty2 = ty + 0.8;
      for (let i = 0; i < 6; i++) {
        const charX = tx - 1.0 + i * 0.35;
        const charDist = Math.sqrt(charX * charX + ty2 * ty2);
        if (charDist < 0.15) {
          height += 0.12 * (1 - charDist / 0.15);
        }
      }
    }

    // Convert to normal
    const scale = 10.0;
    const hx = Math.sin(angle * 20) * 0.015;
    const hy = Math.cos(angle * 20) * 0.015;
    const nx = -hx * scale;
    const ny = -hy * scale;
    const nz = 1.0;
    const len = Math.sqrt(nx*nx + ny*ny + nz*nz);
    return { x: nx/len, y: ny/len, z: nz/len };
  });
}

// Reeded edge normal map
function createEdgeNormalMap() {
  return createNormalMap(512, 128, (u, v) => {
    // u goes around circumference, v goes along height
    const reeds = 120;
    const phase = u * reeds * Math.PI * 2;
    const groove = Math.sin(phase) * 0.5 + 0.5;
    const height = groove * (1 - Math.abs(v - 0.5) * 2) * 0.3;

    const scale = 20.0;
    const hx = Math.cos(phase) * reeds * 0.01;
    const hy = (v < 0.5 ? 1 : -1) * 0.1;
    const nx = -hx * scale;
    const ny = -hy * scale;
    const nz = 1.0;
    const len = Math.sqrt(nx*nx + ny*ny + nz*nz);
    return { x: nx/len, y: ny/len, z: nz/len };
  });
}

// ============================================
// EDITION TILE RENDERER (2D Canvas)
// ============================================
function renderEditionTile(canvas, edition) {
  const ctx = canvas.getContext('2d');
  const dpr = window.devicePixelRatio || 1;
  const size = Math.min(canvas.clientWidth, canvas.clientHeight) || 200;
  canvas.width = size * dpr;
  canvas.height = size * dpr;
  ctx.scale(dpr, dpr);

  const cx = size / 2;
  const cy = size / 2;
  const r = size * 0.42;

  // Metal colors
  const metals = {
    bronze: { base: '#B87333', light: '#CD955C', dark: '#8B5A2B', rim: '#6B4226' },
    silver: { base: '#C0C0C0', light: '#E8E8E8', dark: '#A0A0A0', rim: '#808080' },
    gold: { base: '#FFD700', light: '#FFF8A0', dark: '#CCA300', rim: '#997700' },
    black: { base: '#1A1A1A', light: '#3A3A3A', dark: '#0A0A0A', rim: '#050505' }
  };
  const m = metals[edition];

  // Clear
  ctx.fillStyle = '#0f0f12';
  ctx.fillRect(0, 0, size, size);

  // Drop shadow
  ctx.save();
  ctx.translate(2, 4);
  ctx.beginPath();
  ctx.ellipse(cx, cy, r * 0.9, r * 0.15, 0, 0, Math.PI * 2);
  ctx.fillStyle = 'rgba(0,0,0,0.4)';
  ctx.fill();
  ctx.restore();

  // Coin body - metallic gradient
  const grad = ctx.createRadialGradient(cx - r * 0.3, cy - r * 0.3, 0, cx, cy, r);
  grad.addColorStop(0, m.light);
  grad.addColorStop(0.3, m.base);
  grad.addColorStop(0.7, m.dark);
  grad.addColorStop(1, m.rim);

  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, Math.PI * 2);
  ctx.fillStyle = grad;
  ctx.fill();

  // Reeded edge suggestion
  ctx.strokeStyle = m.rim;
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, Math.PI * 2);
  ctx.stroke();

  // Inner rim
  ctx.strokeStyle = m.light;
  ctx.lineWidth = 1;
  ctx.globalAlpha = 0.5;
  ctx.beginPath();
  ctx.arc(cx, cy, r * 0.92, 0, Math.PI * 2);
  ctx.stroke();
  ctx.globalAlpha = 1;

  // Face design
  if (edition === 'bronze' || edition === 'silver' || edition === 'gold') {
    // Front face emblem
    ctx.save();
    ctx.translate(cx, cy);

    // Outer ring
    ctx.strokeStyle = m.dark;
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.arc(0, 0, r * 0.8, 0, Math.PI * 2);
    ctx.stroke();

    // Inner circle
    ctx.fillStyle = m.base;
    ctx.beginPath();
    ctx.arc(0, 0, r * 0.5, 0, Math.PI * 2);
    ctx.fill();

    // W shape
    ctx.strokeStyle = m.dark;
    ctx.lineWidth = 2.5;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.beginPath();
    const wScale = r * 0.35;
    ctx.moveTo(-wScale, wScale * 0.5);
    ctx.lineTo(-wScale * 0.4, -wScale * 0.5);
    ctx.lineTo(0, 0);
    ctx.lineTo(wScale * 0.4, -wScale * 0.5);
    ctx.lineTo(wScale, wScale * 0.5);
    ctx.stroke();

    // Sunburst lines
    ctx.strokeStyle = m.dark;
    ctx.lineWidth = 1;
    ctx.globalAlpha = 0.4;
    for (let i = 0; i < 16; i++) {
      const a = i * Math.PI / 8;
      const r1 = r * 0.55;
      const r2 = r * 0.75;
      ctx.beginPath();
      ctx.moveTo(Math.cos(a) * r1, Math.sin(a) * r1);
      ctx.lineTo(Math.cos(a) * r2, Math.sin(a) * r2);
      ctx.stroke();
    }
    ctx.globalAlpha = 1;

    ctx.restore();
  } else {
    // Black edition - obsidian void with gold accent
    ctx.save();
    ctx.translate(cx, cy);

    // Outer ring
    ctx.strokeStyle = '#3A3A3A';
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.arc(0, 0, r * 0.8, 0, Math.PI * 2);
    ctx.stroke();

    // Inner void
    const voidGrad = ctx.createRadialGradient(0, 0, 0, 0, 0, r * 0.5);
    voidGrad.addColorStop(0, '#050505');
    voidGrad.addColorStop(1, '#1A1A1A');
    ctx.fillStyle = voidGrad;
    ctx.beginPath();
    ctx.arc(0, 0, r * 0.5, 0, Math.PI * 2);
    ctx.fill();

    // Gold accent ring
    ctx.strokeStyle = '#C9A84C';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.arc(0, 0, r * 0.5, 0, Math.PI * 2);
    ctx.stroke();

    // Central mark
    ctx.fillStyle = '#C9A84C';
    ctx.beginPath();
    ctx.arc(0, 0, r * 0.12, 0, Math.PI * 2);
    ctx.fill();

    ctx.restore();
  }

  // Specular highlight
  const highlight = ctx.createRadialGradient(cx - r * 0.4, cy - r * 0.4, 0, cx - r * 0.4, cy - r * 0.4, r * 0.6);
  highlight.addColorStop(0, 'rgba(255,255,255,0.3)');
  highlight.addColorStop(1, 'rgba(255,255,255,0)');
  ctx.fillStyle = highlight;
  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, Math.PI * 2);
  ctx.fill();
}

// ============================================
// HERO COIN RENDERER (Three.js WebGL)
// ============================================
class HeroCoin {
  constructor(canvas) {
    this.canvas = canvas;
    this.renderer = new THREE.WebGLRenderer({ canvas, antialias: true, alpha: true });
    this.renderer.initTextures();
    this.renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));

    this.scene = new THREE.Scene();
    this.camera = new THREE.PerspectiveCamera(35, 1, 0.1, 100);
    this.camera.position.set(0, 0, 3.5);

    this.coinGroup = new THREE.Object3D();
    this.scene.add(this.coinGroup);

    this._createCoin();
    this._createLights();

    this.time = 0;
    this.paused = false;
    this.animId = null;

    this.resize();
    window.addEventListener('resize', () => this.resize());
  }

  _createCoin() {
    // Coin dimensions
    const radius = 1.0;
    const thickness = 0.12;
    const radialSegs = 128;
    const heightSegs = 1;

    // Generate normal maps
    const frontCanvas = createFrontNormalMap();
    const backCanvas = createBackNormalMap();
    const edgeCanvas = createEdgeNormalMap();

    const gl = this.renderer.gl;
    this.frontNormalMap = uploadTexture(gl, frontCanvas);
    this.backNormalMap = uploadTexture(gl, backCanvas);
    this.edgeNormalMap = uploadTexture(gl, edgeCanvas);

    // Materials for each face
    const frontMat = new THREE.MeshStandardMaterial({
      color: new THREE.Color(0xB87333), // bronze base
      roughness: 0.35,
      metalness: 0.9,
      normalMap: this.frontNormalMap,
      normalScale: new THREE.Vector2(1.5, 1.5),
      envMap: this.renderer._envTexture,
      envMapIntensity: 1.2
    });

    const backMat = new THREE.MeshStandardMaterial({
      color: new THREE.Color(0xB87333),
      roughness: 0.35,
      metalness: 0.9,
      normalMap: this.backNormalMap,
      normalScale: new THREE.Vector2(1.5, 1.5),
      envMap: this.renderer._envTexture,
      envMapIntensity: 1.2
    });

    const edgeMat = new THREE.MeshStandardMaterial({
      color: new THREE.Color(0x8B5A2B),
      roughness: 0.4,
      metalness: 0.95,
      normalMap: this.edgeNormalMap,
      normalScale: new THREE.Vector2(2.0, 2.0),
      envMap: this.renderer._envTexture,
      envMapIntensity: 1.5
    });

    // Create coin as cylinder with multiple material groups
    const geom = THREE.CylinderGeometry(radius, radius, thickness, radialSegs, heightSegs, false, 0, Math.PI * 2);

    // Assign material indices: 0=side, 1=top, 2=bottom
    // Three.js cylinder: side faces first, then top cap, then bottom cap
    const posCount = geom.attributes.position.count;
    const sideCount = radialSegs * heightSegs * 2 * 3; // approximate
    // Actually, let's use groups
    geom.groups = [
      { start: 0, count: radialSegs * heightSegs * 6, materialIndex: 0 }, // side
      { start: radialSegs * heightSegs * 6, count: (radialSegs + 1) * 3, materialIndex: 1 }, // top
      { start: radialSegs * heightSegs * 6 + (radialSegs + 1) * 3, count: (radialSegs + 1) * 3, materialIndex: 2 } // bottom
    ];

    this.coinMesh = new THREE.Mesh(geom, [edgeMat, frontMat, backMat]);
    this.coinGroup.add(this.coinMesh);

    // Store materials for potential updates
    this.materials = { front: frontMat, back: backMat, edge: edgeMat };
  }

  _createLights() {
    // Key light
    const keyLight = new THREE.DirectionalLight(0xFFF5E0, 3.0);
    keyLight.position.set(0.5, 2, 1.5);
    this.scene.add(keyLight);

    // Fill light
    const fillLight = new THREE.DirectionalLight(0x406080, 0.8);
    fillLight.position.set(-1, 0.5, -1);
    this.scene.add(fillLight);

    // Rim light
    const rimLight = new THREE.DirectionalLight(0xFFE0A0, 1.5);
    rimLight.position.set(0, -1, -2);
    this.scene.add(rimLight);
  }

  resize() {
    const rect = this.canvas.getBoundingClientRect();
    const width = rect.width;
    const height = rect.height;
    this.renderer.setSize(width, height);
    this.camera.aspect = width / height;
    this.camera.updateProjectionMatrix();
  }

  setTime(t) {
    this.time = t;
    this._updateCoin(t);
    this.renderer.render(this.scene, this.camera);
  }

  _updateCoin(t) {
    // One full loop: rotate Y 360° AND flip X 360°
    // So both faces visible during loop
    const yRot = t * Math.PI * 2;
    const xRot = t * Math.PI * 2;

    this.coinGroup.rotation.y = yRot;
    this.coinGroup.rotation.x = xRot;

    // Add slight wobble for realism
    this.coinGroup.rotation.z = Math.sin(t * Math.PI * 4) * 0.02;
  }

  pause() {
    this.paused = true;
    if (this.animId) {
      cancelAnimationFrame(this.animId);
      this.animId = null;
    }
  }

  resume() {
    if (this.paused) {
      this.paused = false;
      this._animate();
    }
  }

  _animate() {
    if (this.paused) return;
    const now = performance.now() / 1000;
    // 8 second loop
    const t = (now * 0.125) % 1;
    this.setTime(t);
    this.animId = requestAnimationFrame(() => this._animate());
  }

  start() {
    this._animate();
  }
}

